// 2.8.x | 2023-04-30 | raj  | STRY0138448 - Apply ACL to New Template/Template Subtask Form for Offices and Members in Private Structure

//RJ TEMPLATE PERMISSIONS UPDATE
//STRY0158283
var templateId = current.getValue("routing_template_ref") || '';
// STRY0146507 - Certification Failed Test Resutls - NOT FIXING - Task permissions drives Task Response permissions
var grTemplate = new GlideRecord("x_153465_discovert_discover_routing_template");
var allow = false;
if(templateId !=''){
	if(grTemplate.get(templateId)){
		allow = grTemplate.canRead();
	}
}
answer = allow;
